// --- Handler ---

async function upsertTable(table: string, rows: Record<string, unknown>[]) {
  if (rows.length === 0) return { count: 0, error: null };

  const { data, error } = await supabaseQuery<unknown[]>(table, {
    method: 'POST',
    body: rows,
    upsert: true,
  });

  return { count: Array.isArray(data) ? data.length : 0, error };
}

export default async function handler(_req: VercelRequest, res: VercelResponse) {
  if (_req.method !== 'POST') {
    return res.status(405).json({ error: 'POST only' });
  }

  const results: Record<string, { count: number; error: string | null }> = {};

  // Suppliers (TEXT PK — keep id)
  results.suppliers = await upsertTable('suppliers', SUPPLIERS);

  // Contracts (TEXT PK — keep id)
  results.contracts = await upsertTable('contracts', CONTRACTS);

  // Purchase orders (TEXT PK — keep id)
  results.purchase_orders = await upsertTable(
    'purchase_orders',
    PURCHASE_ORDERS.map((po) => ({
      ...po,
      line_items: JSON.stringify(po.line_items),
    })),
  );

  // Invoices (TEXT PK — keep id)
  results.invoices = await upsertTable('invoices', INVOICES);

  // Compliance reports (UUID auto-id — strip id)
  results.compliance_reports = await upsertTable(
    'compliance_reports',
    COMPLIANCE_REPORTS.map((r) => ({
      ...r,
      checks: JSON.stringify(r.checks),
    })),
  );

  // System integrations (UUID auto-id — strip id)
  results.system_integrations = await upsertTable('system_integrations', SYSTEM_INTEGRATIONS);

  // Approval entries (UUID auto-id — strip id)
  results.approval_entries = await upsertTable('approval_entries', APPROVAL_ENTRIES);

  // Notifications (UUID auto-id — strip id)
  results.notifications = await upsertTable('notifications', NOTIFICATIONS);

  const hasErrors = Object.values(results).some((r) => r.error);

  return res.status(hasErrors ? 207 : 200).json({
    message: hasErrors ? 'Seeded with some errors' : 'All remaining tables seeded',
    results,
  });
}
